class Solution:
    def digitSum(self, s, k):
        while len(s) > k:
            groups = []
            i = 0
            while i < len(s):
                chunk = s[i:i + k]
                total = 0
                for ch in chunk:
                    total += int(ch)
                groups.append(str(total))
                i += k
            s = ''.join(groups)
        return s

