var digitSum = function(s, k) {
    while (s.length > k) {
        let out = '';
        for (let i = 0; i < s.length; i += k) {
            let total = 0;
            for (let j = i; j < Math.min(i + k, s.length); j++) {
                total += s.charCodeAt(j) - 48;
            }
            out += String(total);
        }
        s = out;
    }
    return s;
};
